const fs = require('fs');
const path = '/Users/orion/Documents/大都会-通联';
const items = fs.readdirSync(items, { withFileTypes: true });
items.forEach(item => {
  const stats = fs.statSync(path + '/' + item.name);
  console.log(`${item.isDirectory() ? '[目录]' : '[文件]'} ${item.name}  (${(stats.size / 1024).toFixed(1)} KB)`);
});
console.log('---');
// 也检查会话目录
const sessionPath = '/Users/orion/.llmwork/chats/1782606789429';
if (fs.existsSync(sessionPath)) {
  const sessionItems = fs.readdirSync(sessionPath, { withFileTypes: true });
  console.log('会话目录文件:');
  sessionItems.forEach(item => {
    const stats = fs.statSync(sessionPath + '/' + item.name);
    console.log(`  [${item.isDirectory() ? '目录' : '文件'}] ${item.name}  (${(stats.size / 1024).toFixed(1)} KB)`);
  });
} else {
  console.log('会话目录不存在');
}

